# PER_CHAT_PARALLEL_V1 — per-chat-id worker pool. Each chat_id gets a dedicated
# thread so a slow Claude call in one chat does not block others. Within a
# chat, messages still process sequentially (preserves ordering).
_chat_queues = {}
_chat_queues_lock = threading.Lock()

def _chat_worker(chat_id, q):
    while True:
        try:
            item = q.get()
            if item is None:
                continue
            line, idx = item
            try:
                process_line(line, idx)
            except Exception as e:
                try:
                    log(ERR_LOG, f"worker[{chat_id[:18]}] L{idx}: {e}")
                except Exception:
                    pass
            finally:
                q.task_done()
        except Exception as e:
            try:
                log(ERR_LOG, f"worker[{chat_id[:18]}] outer: {e}")
            except Exception:
                pass

def _dispatch_to_worker(line, idx):
    try:
        env = json.loads(line)
        body = json.loads(env.get("body", "{}"))
        cid = (body.get("conversation") or {}).get("id", "") or "_default"
    except Exception:
        cid = "_default"
    with _chat_queues_lock:
        if cid not in _chat_queues:
            q = queue.Queue()
            _chat_queues[cid] = q
            t = threading.Thread(target=_chat_worker, args=(cid, q),
                                 daemon=True, name=f"chat-{cid[:18]}")
            t.start()
        q = _chat_queues[cid]
    q.put((line, idx))


